Scripts.OnLoad:
self:RegisterForClicks("LeftButtonUp", "RightButtonUp");
self:SetAttribute("useOnKeyDown", false);
self:SetAttribute("type1", "macro");
self:SetAttribute("macrotext", "/targetexact nil");

Scripts.OnUpdate:
if Spy2.EnabledInZone and GameTooltip:IsOwned(Minimap) and (Spy2.db.profile.MinimapDetection or Spy2.db.profile.MinimapDetails) then
	Spy2:TrackHumanoids();
end
